"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[8177],{20136(n,r,t){t.r(r),t.d(r,{assets:()=>i,contentTitle:()=>c,default:()=>p,frontMatter:()=>d,metadata:()=>e,toc:()=>a});const e=JSON.parse('{"id":"cpp17/ctad","title":"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)","description":"C++17 \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/03-ctad.md","sourceDirName":"cpp17","slug":"/cpp17/03-ctad","permalink":"/LearnModernCpp/docs/cpp17/03-ctad","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"ctad","permalink":"/LearnModernCpp/docs/tags/ctad"}],"version":"current","sidebarPosition":4,"frontMatter":{"sidebar_position":4,"slug":"03-ctad","title":"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)","description":"C++17 \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","ctad"]},"sidebar":"docs","previous":{"title":"if/switch \u4e2d\u7684\u521d\u59cb\u5316\u8bed\u53e5 (Init Statements)","permalink":"/LearnModernCpp/docs/cpp17/02-if-switch-init"},"next":{"title":"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)","permalink":"/LearnModernCpp/docs/cpp17/04-fold-expressions"}}');var s=t(74848),o=t(28453);const d={sidebar_position:4,slug:"03-ctad",title:"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)",description:"C++17 \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","ctad"]},c="\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)",i={},a=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(r.header,{children:(0,s.jsx)(r.h1,{id:"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc-ctad-class-template-argument-deduction",children:"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)"})}),"\n",(0,s.jsx)(r.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(r.pre,{children:(0,s.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp17/03_ctad.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u7f16\u8bd1\u5668\u53ef\u4ee5\u4ece\u6784\u9020\u51fd\u6570\u7684\u53c2\u6570\u81ea\u52a8\u63a8\u5bfc\u7c7b\u6a21\u677f\u53c2\u6570\uff0c\r\n *          \u65e0\u9700\u663e\u5f0f\u6307\u5b9a\u6a21\u677f\u53c2\u6570\u3002\u4f8b\u5982 std::pair p{1, 2.0};\r\n *          \u81ea\u52a8\u63a8\u5bfc\u4e3a std::pair<int, double>\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++14 \u4e2d\u4f7f\u7528 pair<int,double>{1, 2.0} \u6216\r\n *              make_pair(1, 2.0) \u90fd\u4e0d\u591f\u7b80\u6d01\u3002CTAD \u8ba9\u7c7b\u6a21\u677f\r\n *              \u7684\u4f7f\u7528\u4f53\u9a8c\u548c\u51fd\u6570\u6a21\u677f\u4e00\u6837\u81ea\u7136\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u6807\u51c6\u5e93\u7c7b\u578b pair/tuple/vector/optional \u7b49\u90fd\u652f\u6301 CTAD\r\n *   - \u53ef\u4ee5\u4e3a\u81ea\u5b9a\u4e49\u7c7b\u7f16\u5199\u300c\u63a8\u5bfc\u6307\u5f15\u300d(deduction guide)\r\n *   - CTAD \u8ba9 make_xxx \u7cfb\u5217\u8f85\u52a9\u51fd\u6570\u4e0d\u518d\u5fc5\u8981\r\n *   - \u6ce8\u610f\uff1astd::vector v{1,2,3} \u63a8\u5bfc\u4e3a vector<int>\uff0c\r\n *     \u4f46 std::vector v{"hello"} \u63a8\u5bfc\u4e3a vector<const char*>\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <utility>\r\n#include <tuple>\r\n#include <optional>\r\n#include <array>\r\n#include <mutex>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // 1. std::pair \u2014\u2014 \u4e0d\u9700\u8981\u5199 pair<int, double>\r\n    std::pair p{42, 3.14};     // \u63a8\u5bfc\u4e3a pair<int, double>\r\n    std::cout << "pair: " << p.first << ", " << p.second << "\\n";\r\n\r\n    // 2. std::tuple \u2014\u2014 \u4e0d\u9700\u8981\u5199 tuple<int, double, string>\r\n    std::tuple t{1, 2.0, std::string("hello")};\r\n    std::cout << "tuple: " << std::get<0>(t) << ", "\r\n              << std::get<1>(t) << ", " << std::get<2>(t) << "\\n";\r\n\r\n    // 3. std::vector \u2014\u2014 \u4ece\u521d\u59cb\u5316\u5217\u8868\u63a8\u5bfc\u5143\u7d20\u7c7b\u578b\r\n    std::vector v{1, 2, 3, 4, 5};  // \u63a8\u5bfc\u4e3a vector<int>\r\n    std::cout << "vector<int> \u5927\u5c0f: " << v.size() << "\\n";\r\n\r\n    // 4. std::optional\r\n    std::optional opt{42};  // \u63a8\u5bfc\u4e3a optional<int>\r\n    std::cout << "optional: " << opt.value() << "\\n";\r\n\r\n    // 5. std::array\uff08C++17 \u652f\u6301\u63a8\u5bfc\uff09\r\n    std::array arr{1, 2, 3};  // \u63a8\u5bfc\u4e3a array<int, 3>\r\n    std::cout << "array \u5927\u5c0f: " << arr.size() << "\\n";\r\n\r\n    // 6. \u4e0e make_xxx \u7684\u5bf9\u6bd4\r\n    //    C++14 \u5199\u6cd5\uff1a\r\n    auto p14 = std::make_pair(42, 3.14);\r\n    auto t14 = std::make_tuple(1, 2.0, std::string("hello"));\r\n    //    C++17 \u5199\u6cd5\uff1a\u76f4\u63a5\u6784\u9020\uff0c\u65e0\u9700\u8f85\u52a9\u51fd\u6570\r\n    std::pair p17{42, 3.14};\r\n    std::tuple t17{1, 2.0, std::string("hello")};\r\n    std::cout << "make_pair \u4e0e CTAD \u7ed3\u679c\u76f8\u540c: "\r\n              << (p14 == p17 ? "\u662f" : "\u5426") << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u81ea\u5b9a\u4e49\u7c7b\u7684\u63a8\u5bfc\u6307\u5f15\r\n// ============================================================\r\n\r\n// \u7b80\u5355\u5bb9\u5668\u7c7b\r\ntemplate<typename T>\r\nclass MyContainer {\r\npublic:\r\n    MyContainer(T value, int count)\r\n        : value_(value), count_(count) {}\r\n\r\n    void print() const {\r\n        for (int i = 0; i < count_; ++i) {\r\n            std::cout << value_ << " ";\r\n        }\r\n        std::cout << "\\n";\r\n    }\r\n\r\nprivate:\r\n    T value_;\r\n    int count_;\r\n};\r\n\r\n// \u81ea\u5b9a\u4e49\u63a8\u5bfc\u6307\u5f15\uff1a\u4ece C \u5b57\u7b26\u4e32\u63a8\u5bfc\u4e3a std::string \u7248\u672c\r\nMyContainer(const char*, int) -> MyContainer<std::string>;\r\n\r\n// \u53e6\u4e00\u4e2a\u4f8b\u5b50\uff1a\u52a0\u6cd5\u5668\r\ntemplate<typename T>\r\nstruct Adder {\r\n    T value;\r\n    Adder(T v) : value(v) {}\r\n    T add(T other) const { return value + other; }\r\n};\r\n// \u63a8\u5bfc\u6307\u5f15\uff08\u8fd9\u91cc\u5176\u5b9e\u7f16\u8bd1\u5668\u80fd\u81ea\u52a8\u751f\u6210\uff0c\u53ea\u662f\u5c55\u793a\u8bed\u6cd5\uff09\r\ntemplate<typename T>\r\nAdder(T) -> Adder<T>;\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // 1. \u81ea\u5b9a\u4e49\u7c7b\u7684 CTAD\r\n    MyContainer c1{42, 3};           // \u63a8\u5bfc\u4e3a MyContainer<int>\r\n    MyContainer c2{"hello", 2};      // \u901a\u8fc7\u63a8\u5bfc\u6307\u5f15 -> MyContainer<std::string>\r\n    std::cout << "MyContainer<int>: ";\r\n    c1.print();\r\n    std::cout << "MyContainer<string>: ";\r\n    c2.print();\r\n\r\n    // 2. Adder \u7684 CTAD\r\n    Adder a{3.14};  // \u63a8\u5bfc\u4e3a Adder<double>\r\n    std::cout << "Adder: " << a.add(1.86) << "\\n";\r\n\r\n    // 3. std::lock_guard \u4e5f\u652f\u6301 CTAD\r\n    std::mutex mtx;\r\n    {\r\n        std::lock_guard lock{mtx};  // \u4e0d\u9700\u8981\u5199 lock_guard<mutex>\r\n        std::cout << "lock_guard CTAD: \u4e0d\u9700\u8981\u6307\u5b9a mutex \u7c7b\u578b\\n";\r\n    }\r\n\r\n    // 4. \u62f7\u8d1d\u63a8\u5bfc \u2014\u2014 \u4ece\u540c\u7c7b\u578b\u5bb9\u5668\u63a8\u5bfc\r\n    std::vector original{1, 2, 3};\r\n    std::vector copy{original};  // \u63a8\u5bfc\u4e3a vector<int>\uff0c\u62f7\u8d1d\u6784\u9020\r\n    std::cout << "\u62f7\u8d1d\u63a8\u5bfc: \u5927\u5c0f=" << copy.size() << "\\n";\r\n\r\n    // 5. pair \u5d4c\u5957\u63a8\u5bfc\r\n    std::pair nested{std::pair{1, 2}, std::string("nested")};\r\n    std::cout << "\u5d4c\u5957 pair: ((" << nested.first.first\r\n              << "," << nested.first.second\r\n              << "), " << nested.second << ")\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: const char* vs std::string\r\n    std::vector v1{"hello", "world"};  // vector<const char*>\uff0c\u4e0d\u662f vector<string>\uff01\r\n    // \u5982\u679c\u60f3\u8981 vector<string>\uff0c\u9700\u8981\u663e\u5f0f\u6307\u5b9a\uff1a\r\n    std::vector<std::string> v2{"hello", "world"};\r\n    std::cout << "\u9677\u96311 - v1 \u662f vector<const char*>\uff0cv2 \u662f vector<string>\\n";\r\n\r\n    // \u9677\u9631 2: \u5355\u5143\u7d20 vector \u7684\u6b67\u4e49\r\n    std::vector v3{5};       // vector<int>\uff0c\u5305\u542b\u4e00\u4e2a\u5143\u7d20 5\r\n    std::vector v4(5, 0);    // vector<int>\uff0c\u5305\u542b\u4e94\u4e2a 0\r\n    std::cout << "\u9677\u96312 - v3 \u5927\u5c0f=" << v3.size()\r\n              << ", v4 \u5927\u5c0f=" << v4.size() << "\\n";\r\n\r\n    // \u9677\u9631 3: \u4e0d\u80fd\u5bf9\u7a7a\u5bb9\u5668\u4f7f\u7528 CTAD\uff08\u65e0\u6cd5\u63a8\u5bfc\u7c7b\u578b\uff09\r\n    // std::vector v{};      // \u7f16\u8bd1\u9519\u8bef\uff01\u65e0\u6cd5\u63a8\u5bfc\u5143\u7d20\u7c7b\u578b\r\n    // std::optional o{};    // \u7f16\u8bd1\u9519\u8bef\uff01\r\n    std::cout << "\u9677\u96313 - \u7a7a\u5bb9\u5668\u4e0d\u80fd\u7528 CTAD\uff0c\u5fc5\u987b\u663e\u5f0f\u6307\u5b9a\u7c7b\u578b\\n";\r\n\r\n    // \u9677\u9631 4: \u521d\u59cb\u5316\u5217\u8868 vs \u5355\u503c\r\n    std::vector v5{std::vector{1, 2, 3}};\r\n    // v5 \u662f vector<int>\uff08\u62f7\u8d1d\uff09\uff0c\u4e0d\u662f vector<vector<int>>\uff01\r\n    std::cout << "\u9677\u96314 - \u62f7\u8d1d\u63a8\u5bfc\u4f18\u5148: v5 \u5927\u5c0f=" << v5.size() << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(r.ul,{children:["\n",(0,s.jsx)(r.li,{children:(0,s.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/class_template_argument_deduction",children:"cppreference: \u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)"})}),"\n"]})]})}function p(n={}){const{wrapper:r}={...(0,o.R)(),...n.components};return r?(0,s.jsx)(r,{...n,children:(0,s.jsx)(l,{...n})}):l(n)}},28453(n,r,t){t.d(r,{R:()=>d,x:()=>c});var e=t(96540);const s={},o=e.createContext(s);function d(n){const r=e.useContext(o);return e.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function c(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:d(n.components),e.createElement(o.Provider,{value:r},n.children)}}}]);